{"command":"cd /app/data/auto-opt/utils/llvm-73622 && cat << 'EOF' > patch.py
import re
with open('llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp', 'r') as f:
    content = f.read()

new_code = """  const APInt *MaskC, *CmpC;
  ICmpInst::Predicate Pred;
  if (!match(Add.getOperand(1),
             m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
                           m_APInt(CmpC)))))
    return nullptr;

  APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
  if (*MaskC != (SMin | (*DivC - 1)))
    return nullptr;

  bool IsUGT = Pred == ICmpInst::ICMP_UGT && CmpC->isSignMask();
  bool IsEQ = Pred == ICmpInst::ICMP_EQ && *CmpC == *MaskC && *DivC == 2;
  if (!IsUGT && !IsEQ)
    return nullptr;"""

old_code_regex = r"""  const APInt \*MaskC;
  ICmpInst::Predicate Pred;
  if \(!match\(Add\.getOperand\(1\),
             m_SExt\(m_ICmp\(Pred, m_And\(m_Specific\(X\), m_APInt\(MaskC\)\),
                           m_SignMask\(\)\)\)\) \|\|
      Pred != ICmpInst::ICMP_UGT\)
    return nullptr;

  APInt SMin = APInt::getSignedMinValue\(Add\.getType\(\)->getScalarSizeInBits\(\)\);
  if \(\*MaskC != \(SMin \| \(\*DivC - 1\)\)\)
    return nullptr;"""

content = re.sub(old_code_regex, new_code, content, count=1)

with open('llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp', 'w') as f:
    f.write(content)
EOF
python patch.py"}

